+		}
+
+		expectedSeq := uint64(i + 1)
+		if entry.SequenceNum != expectedSeq {
+			t.Errorf("Entry %d: expected sequence %d, got %d", i, expectedSeq, entry.SequenceNum)
+		}
+	}
+}
