+func TestSendOutputSchemaStability(t *testing.T) {
+	// Test schema consistency across multiple calls
+	output1 := SendOutput{
+		RobotResponse:  NewRobotResponse(true),
+		Session:        "test-session",
+		SentAt:         time.Now().UTC(),
+		Targets:        []string{"0", "1", "2"},
+		Successful:     []string{"0", "1"},
